mapper.select:
WITH ValidTicketList AS ( SELECT SR_MST.SRType, SR_MST.CompletionDT, SR_MST.ClientID FROM XBOLTAPP.ESM_SR_MST SR_MST INNER JOIN XBOLTAPP.ESM_SR_TYPE SRTP_TBL ON SR_MST.SRType = SRTP_TBL.SRTypeCode INNER JOIN XBOLTADM.TB_ITEM PART_ITEM ON SR_MST.SRArea2 = PART_ITEM.ItemID INNER JOIN XBOLTAPP.CRM_CUST_MST CUSTMST ON SR_MST.ClientID = CUSTMST.CustomerNo WHERE SR_MST.SRID IS NOT NULL AND SR_MST.SRCode IS NOT NULL AND SRTP_TBL.Deactivated = '0' AND SRTP_TBL.ProcModelID IS NOT NULL AND PART_ITEM.ClassCode = 'CL04002' AND PART_ITEM.Deleted = 0 AND CUSTMST.CustLvl = 'C'
AND SR_MST.RegDT >= CAST(#{regStartDate} AS DATETIME)
AND SR_MST.RegDT <= DATEADD(MS, -2, DATEADD(DAY, 1, CAST(#{regEndDate} AS DATETIME)))
AND SR_MST.ClientID = #{clientName}
) SELECT TEAMTXT.Name AS ClientName, COUNT(VTL.SRType) AS ClientTotal, SUM(CASE WHEN VTL.SRType IS NOT NULL AND VTL.CompletionDT IS NOT NULL THEN 1 ELSE 0 END) AS ClientCompleted, SUM(CASE WHEN VTL.SRType IS NOT NULL AND VTL.CompletionDT IS NULL THEN 1 ELSE 0 END) AS ClientProcessing,
SUM(CASE WHEN VTL.SRType = #{srType} THEN 1 ELSE 0 END) AS "${srType}Total", SUM(CASE WHEN VTL.SRType = #{srType} AND VTL.CompletionDT IS NOT NULL THEN 1 ELSE 0 END) AS "${srType}Completed", SUM(CASE WHEN VTL.SRType = #{srType} AND VTL.CompletionDT IS NULL THEN 1 ELSE 0 END) AS "${srType}Processing"
FROM XBOLTAPP.CRM_CUST_MST CUSTMST INNER JOIN XBOLTADM.TB_TEAM_TXT TEAMTXT ON TEAMTXT.TeamID = CUSTMST.TeamID LEFT OUTER JOIN ValidTicketList VTL ON VTL.ClientID = CUSTMST.CustomerNo WHERE CUSTMST.CustLvl = 'C' AND TEAMTXT.LanguageID = #{languageID} GROUP BY TEAMTXT.Name ORDER BY ClientName;

WITH ValidTicketList AS ( SELECT SR_MST.SRID, SR_MST.SRCode, SR_MST.SRType, SR_MST.CompletionDT, SR_MST.SRArea2, SR_MST.ClientID FROM XBOLTAPP.ESM_SR_MST SR_MST INNER JOIN XBOLTAPP.ESM_SR_TYPE SRTP_TBL ON SR_MST.SRType = SRTP_TBL.SRTypeCode INNER JOIN XBOLTADM.TB_ITEM PART_ITEM ON SR_MST.SRArea2 = PART_ITEM.ItemID INNER JOIN XBOLTAPP.CRM_CUST_MST CUSTMST ON SR_MST.ClientID = CUSTMST.CustomerNo WHERE SR_MST.SRID IS NOT NULL AND SR_MST.SRCode IS NOT NULL AND SRTP_TBL.Deactivated = '0' AND SRTP_TBL.ProcModelID IS NOT NULL AND PART_ITEM.ClassCode = 'CL04002' AND PART_ITEM.Deleted = 0 AND CUSTMST.CustLvl = 'C'
AND SR_MST.RegDT >= CAST(#{regStartDate} AS DATETIME)
AND SR_MST.RegDT <= DATEADD(MS, -2, DATEADD(DAY, 1, CAST(#{regEndDate} AS DATETIME)))
AND SR_MST.ClientID = #{customerNo}
AND SR_MST.SRType IN
#{srType}
), SumQuery AS ( SELECT VTL.SRArea2 AS PartID, COUNT(VTL.SRCode) AS Total, SUM(CASE WHEN VTL.SRType IS NOT NULL AND VTL.CompletionDT IS NOT NULL THEN 1 ELSE 0 END) AS Completed, SUM(CASE WHEN VTL.SRType IS NOT NULL AND VTL.CompletionDT IS NULL THEN 1 ELSE 0 END) AS Processing
, SUM(CASE WHEN VTL.SRType = #{srType} THEN 1 ELSE 0 END) AS "${srType}Total", SUM(CASE WHEN VTL.SRType = #{srType} AND VTL.CompletionDT IS NOT NULL THEN 1 ELSE 0 END) AS "${srType}Completed", SUM(CASE WHEN VTL.SRType = #{srType} AND VTL.CompletionDT IS NULL THEN 1 ELSE 0 END) AS "${srType}Processing"
FROM ValidTicketList VTL GROUP BY VTL.SRArea2 ) SELECT PARENT_ATR.PlainText AS ServiceName, PART_ATR.PlainText AS PartName, PART_ITEM.ItemID AS PartID, COALESCE(SumQuery.Total, 0) AS Total, COALESCE(SumQuery.Completed, 0) AS Completed, COALESCE(SumQuery.Processing, 0) AS Processing
, COALESCE(SumQuery.${srType}Total, 0) AS "${srType}Total", COALESCE(SumQuery.${srType}Completed, 0) AS "${srType}Completed", COALESCE(SumQuery.${srType}Processing, 0) AS "${srType}Processing"
FROM XBOLTADM.TB_ITEM PART_ITEM LEFT OUTER JOIN SumQuery ON PART_ITEM.ItemID = SumQuery.PartID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR PART_ATR ON PART_ITEM.ItemID = PART_ATR.ItemID AND PART_ATR.AttrTypeCode = 'AT00001' AND PART_ATR.LanguageID = #{languageID} LEFT OUTER JOIN XBOLTADM.TB_ITEM CXN ON PART_ITEM.ItemID = CXN.ToItemID LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR PARENT_ATR ON CXN.FromItemID = PARENT_ATR.ItemID AND PARENT_ATR.AttrTypeCode = 'AT00001' AND PARENT_ATR.LanguageID = #{languageID} WHERE PART_ITEM.ClassCode = 'CL04002' AND PART_ITEM.Deleted = 0 ORDER BY PARENT_ATR.PlainText, PART_ITEM.ItemID;

SELECT ISNULL(Total,0) AS Total, ISNULL(Unassigned,0) AS Unassigned, ISNULL(Completed,0) AS Completed, ISNULL(Delayed,0) AS Delayed FROM ( SELECT SUM(CASE WHEN Blocked = 0 AND IsPublic = 1 AND ( (ReceiptUserID IS NULL AND CompletionDT IS NULL)OR (ReceiptUserID IS NOT NULL AND CompletionDT IS NULL AND (Duedate IS NULL OR Duedate > CAST(GETDATE() AS DATE)))OR (Duedate < CAST(ISNULL(CompletionDT,GETDATE()) AS DATE)) )THEN 1 ELSE 0 END ) AS Total, SUM(CASE WHEN ReceiptUserID IS NULL AND CompletionDT IS NULL AND Blocked = 0 AND IsPublic = 1 THEN 1 ELSE 0 END) AS Unassigned, SUM(CASE WHEN ReceiptUserID IS NOT NULL AND CompletionDT IS NULL AND Blocked = 0 AND IsPublic = 1 AND (Duedate IS NULL OR Duedate > CAST(GETDATE() AS DATE)) THEN 1 ELSE 0 END) AS Completed, SUM(CASE WHEN Duedate < CAST(ISNULL(CompletionDT,GETDATE()) AS DATE) AND Blocked = 0 AND IsPublic = 1 THEN 1 ELSE 0 END) AS Delayed FROM XBOLTAPP.ESM_SR_MST
AND ClientID = #{clientID}
AND CustGRNo in (${custGRNo})
AND ReceiptTeamID = #{receiptTeamID}
AND ReceiptUserID = #{receiptUserID}
) T

Select * INTO #temp_result FROM ( SELECT Row_Number()OVER(ORDER BY TBD.RegDTOrg DESC ) as RNUM, TBD.* From ( Select TSM.SRID TSM_SRID , TSM.RegDT RegDTOrg , TIS.ItemID TIS_ItemID , TISA.seq TISA_seq , TIA.Seq TIA_Seq , SRArea1ATR.seq SRArea1ATR_seq , SRArea２ATR.seq SRArea２ATR_seq From XBOLTAPP.ESM_SR_MST TSM WITH(NOLOCK) Left Outer Join XBOLTADM.TB_ITEM TIS WITH(NOLOCK) ON TSM.Status = TIS.Identifier Left Outer Join XBOLTADM.TB_ITEM_ATTR TISA WITH(NOLOCK) ON TISA.ItemID = TIS.ItemID And TISA.AttrTypeCode = 'AT00001' And TISA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = TSM.SRArea1 And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA2 WITH(NOLOCK) ON TIA2.ItemID = TSM.SRArea2 And TIA2.AttrTypeCode = 'AT00001' And TIA2.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR SRArea1ATR WITH(NOLOCK) ON SRArea1ATR.ItemID = TSM.SRArea1 AND SRArea1ATR.AttrTypeCode = 'AT00035' AND SRArea1ATR.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM_ATTR SRArea２ATR WITH(NOLOCK) ON SRArea２ATR.ItemID = TSM.SRArea2 AND SRArea２ATR.AttrTypeCode = 'AT00035' AND SRArea２ATR.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_MEMBER TM WITH(NOLOCK) ON TSM.ReceiptUserID = TM.MemberID WHERE TSM.isPublic = 1
AND TSM.Blocked = #{blocked}
AND TSM.ReceiptTeamID = #{receiptTeamID}
AND TSM.ReceiptUserID = #{receiptUserID}
AND TM.ClientID = #{clientID}
AND TSM.ClientID = #{srClientID}
AND TSM.CustGRNo in (${custGRNo})
AND TM.ClientID in (${clientIDs})
AND TM.CompanyID in (${companyIDs})
AND TSM.SRType = #{srType}
AND TSM.Category = #{category}
AND TSM.SubCategory = #{subCategory}
AND TSM.SRArea1 = #{srArea1}
AND TSM.SRArea2 = #{srArea2}
AND TSM.SRType in (${srTypes})
AND TSM.Category in (${categories})
AND TSM.SubCategory in (${subCategories})
AND TSM.SRArea1 in (${service})
AND TSM.SRArea2 in (${part})
AND TSM.RegDT BETWEEN CAST(#{regStartDate} AS DATETIME) AND DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{regEndDate} AS DATETIME)))
And( (TSM.ReceiptUserID IS NULL AND TSM.CompletionDT IS NULL) OR (TSM.ReceiptUserID IS NOT NULL AND TSM.CompletionDT IS NULL AND (TSM.Duedate IS NULL OR TSM.Duedate > CAST(GETDATE() AS DATE))) OR (TSM.Blocked = 0 AND TSM.IsPublic = 1 And TSM.Duedate < CAST(ISNULL(TSM.CompletionDT,GETDATE()) AS DATE)) )
And TSM.ReceiptUserID IS NULL AND TSM.CompletionDT IS NULL
And TSM.ReceiptUserID IS NOT NULL AND TSM.CompletionDT IS NULL AND (TSM.Duedate IS NULL OR TSM.Duedate > CAST(GETDATE() AS DATE))
AND TSM.Blocked = 0 AND TSM.IsPublic = 1 And TSM.Duedate < CAST(ISNULL(TSM.CompletionDT,GETDATE()) AS DATE)
) AS TBD ) AS SRTBD
Select tmp.RNUM , TSM.SRCode, TSM.SRID, TSM.Status, TSM.SRType, TSM.ESType, TSM.ReceiptUserID, TEAM6.Name AS CompanyName, TSM.Subject, TIA.PlainText As SRArea1Name, TIA2.PlainText As SRArea2Name, TD4.Name As CategoryNM, ISNULL(TD3.Name, TD4.Name) As SubCategoryNM, ISNULL(CONVERT(char(19),TSM.RegDT, 120),'') as RegDate, TM3.Name + Case When ISNULL(TM3.NameEN,'') != '' Then '(' + ISNULL(TM3.NameEN,'') + ')' Else '' End As ReqUserNM, TM4.Name + Case When ISNULL(TM4.NameEN,'') != '' Then '(' + ISNULL(TM4.NameEN,'') + ')' Else '' End As ReceiptName, TSM.DueDate as DueDate, EAL.StartTime as RCPT_DATE, CASE WHEN TSM.CompletionDT is null THEN CASE WHEN CAST(TSM.Duedate AS DATE) < CAST(GETDATE() AS DATE) THEN CONVERT(INT, DATEDIFF(DAY, TSM.Duedate, GETDATE())) ELSE '0' END WHEN TSM.CompletionDT is not null THEN CASE WHEN CAST(TSM.Duedate AS DATE) < CAST(tsm.CompletionDT AS DATE) THEN CONVERT(INT, DATEDIFF(DAY, TSM.Duedate, tsm.CompletionDT)) ELSE '0' END END as 'delayDay', ISNULL(CONVERT(char(19),TSM.CompletionDT, 120),'') as SRCompletionDT From #temp_result tmp INNER JOIN XBOLTAPP.ESM_SR_MST TSM WITH(NOLOCK) ON tmp.TSM_SRID = TSM.SRID Left Outer Join XBOLTADM.TB_MEMBER TM3 WITH(NOLOCK) On TM3.MemberID = TSM.RequestUserID Left Outer Join XBOLTADM.TB_MEMBER TM4 WITH(NOLOCK) On TM4.MemberID = TSM.ReceiptUserID Left Outer Join XBOLTADM.TB_DICTIONARY TD4 WITH(NOLOCK) On TD4.TypeCode = TSM.Category AND TD4.Category = 'SRCAT' And TD4.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_DICTIONARY TD3 WITH(NOLOCK) On TD3.TypeCode = TSM.SubCategory And TD3.Category = 'SRCAT' And TD3.LanguageID = #{languageID} Left Outer Join XBOLTADM.TB_ITEM TIS WITH(NOLOCK) ON TSM.Status = TIS.Identifier AND tmp.TIS_ItemID = TIS.ItemID Left Outer Join XBOLTADM.TB_ITEM_ATTR TISA WITH(NOLOCK) ON TISA.ItemID = TIS.ItemID And TISA.AttrTypeCode = 'AT00001' And TISA.LanguageID = #{languageID} AND tmp.TISA_seq = TISA.seq Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA WITH(NOLOCK) ON TIA.ItemID = TSM.SRArea1 And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID} AND tmp.TIA_Seq = TIA.Seq Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA2 WITH(NOLOCK) ON TIA2.ItemID = TSM.SRArea2 And TIA2.AttrTypeCode = 'AT00001' And TIA2.LanguageID = #{languageID} Left Outer Join XBOLTAPP.CRM_CUST_MST CCM WITH(NOLOCK) ON TSM.ClientID = CCM.CustomerNo Left Outer Join XBOLTADM.TB_TEAM_TXT TEAM6 WITH(NOLOCK) ON TEAM6.TeamID = CCM.TeamID And TEAM6.LanguageID = #{languageID} Left Outer Join XBOLTAPP.ESM_ACTIVITY_LOG EAL WITH(NOLOCK) ON EAL.PID = TSM.SRID AND EAL.SpeCode = TSM.Status AND EAL.Seq = ( SELECT MAX(Seq) FROM XBOLTAPP.ESM_ACTIVITY_LOG WITH(NOLOCK) WHERE SpeCode = TSM.Status AND PID = TSM.SRID )
ORDER BY tmp.RNUM
DROP TABLE #temp_result

WITH BusinessHourTotals AS ( SELECT SRID, MemberID, SUM(BUSINESS_HOURS) AS TotalBusinessHours FROM XBOLTAPP.ESM_MBR_RCD GROUP BY SRID, MemberID ) SELECT SRMST.SRType, SRMST.SRID, SRMST.SRCode, SRMST.Status, SRMST.ESType, TEAMTEXTCLIENT.Name as ClientName, SRArea01Item.PlainText as SRArea1, SRArea02Item.PlainText as SRArea2, CatDic.Name as Category, SubcatDic.Name as Subcategory, SRMST.Subject as Title, CONVERT(DATE, SRMST.RegDT) AS RegDT, RegUser.Name as RegUserName, CONVERT(DATE, TrimmedActivityLog.StartTime) AS ReceiptDate, SRMST.ReceiptUserID, ReceiptUser.Name as ReceiptUserName, ISNULL(CONVERT(char(10),SRMST.DueDate, 120),'') AS DueDate, ISNULL(CONVERT(char(10),SRMST.CompletionDT, 120),'') AS CompletionDT, CASE WHEN SRMST.CompletionDT IS NULL THEN NULL WHEN CONVERT(DATE, SRMST.CompletionDT) <= CONVERT(DATE, SRMST.DueDate) THEN 0 ELSE DATEDIFF(day, CONVERT(DATE, SRMST.DueDate), CONVERT(DATE, SRMST.CompletionDT)) END AS DelayedDays, SRMST.SRID, ISNULL(BHT.TotalBusinessHours, 0) AS TotalBusinessHours FROM XBOLTAPP.ESM_SR_MST SRMST
INNER JOIN XBOLTAPP.CRM_CUST_MST CUSTMST ON CUSTMST.CustomerNo = SRMST.ClientID
INNER JOIN XBOLTADM.TB_TEAM_TXT TEAMTEXTCLIENT ON TEAMTEXTCLIENT.TeamID = CUSTMST.TeamID AND TEAMTEXTCLIENT.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR SRArea01Item ON SRArea01Item.ItemID = SRMST.SRArea1 AND SRArea01Item.AttrTypeCode = 'AT00001' AND SRArea01Item.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR SRArea02Item ON SRArea02Item.ItemID = SRMST.SRArea2 AND SRArea02Item.AttrTypeCode = 'AT00001' AND SRArea02Item.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY CatDic ON CatDic.TypeCode = SRMST.Category AND CatDic.Category = 'SRCAT' AND CatDic.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_DICTIONARY SubcatDic ON SubcatDic.TypeCode = SRMST.SubCategory AND SubcatDic.Category = 'SRCAT' AND SubcatDic.LanguageID = #{languageID}
LEFT OUTER JOIN XBOLTADM.TB_MEMBER RegUser ON SRMST.RegUserID = RegUser.MemberID
LEFT OUTER JOIN XBOLTADM.TB_MEMBER ReceiptUser ON SRMST.ReceiptUserID = ReceiptUser.MemberID
LEFT OUTER JOIN ( SELECT DocumentID, ActorID, StartTime, ROW_NUMBER() OVER ( PARTITION BY DocumentID, ActorID ORDER BY StartTime DESC ) AS rn FROM XBOLTAPP.ESM_ACTIVITY_LOG ) TrimmedActivityLog ON SRMST.SRID = TrimmedActivityLog.DocumentID AND SRMST.ReceiptUserID = TrimmedActivityLog.ActorID AND TrimmedActivityLog.rn = 1 LEFT OUTER JOIN BusinessHourTotals BHT ON BHT.SRID = SRMST.SRID AND BHT.MemberID = SRMST.ReceiptUserID WHERE SRMST.ReceiptUserID IS NOT NULL
AND ReceiptUser.ClientID = #{clientID}
AND ReceiptUser.ClientID in (${clientIDs})
AND SRMST.CompanyID in (${companyIDs})
AND SRMST.ReceiptUserID = #{managerID}
AND SRMST.RegDT >= CAST(#{regStartDate} AS DATETIME)
AND SRMST.RegDT <= DATEADD(MS, -2, DATEADD(DAY,1,CAST(#{regEndDate} AS DATETIME)))
AND SRMST.ReceiptTeamID = #{receiptTeamID}
